# Worker — runs all heavy processing off the main (GUI) thread
# ══════════════════════════════════════════════════════════════════════════════
class ProcessingWorker(QThread):
    # signals: (percent 0-100, status message)
    progress  = pyqtSignal(int, str)
    finished  = pyqtSignal(dict)          # emits result dict on success
    error     = pyqtSignal(str)           # emits error message on failure

    def __init__(self, org_data, df_input):
        super().__init__()
        self.org_data = org_data
        self.df_input = df_input

    def run(self):
        try:
            org_data = self.org_data
            df_input = self.df_input

            # ── Stage 1: compute TD / PD / global indices ──────────────────
            self.progress.emit(5, "Computing total deviation (TD)…")
            df_td, df_tdp, df_gi, df_gip, df_pd, df_pdp, gh = \
                visualFields.getallvalues(df_input)

            self.progress.emit(20, "Renaming output columns…")
            def _to_s(df):
                rmap = {c: f's{c[1:]}' for c in df.columns
                        if len(c) >= 2 and c[0] in ('l','p') and c[1:].isdigit()}
                return df.rename(columns=rmap) if rmap else df

            df_td  = _to_s(df_td);  df_tdp = _to_s(df_tdp)
            df_pd  = _to_s(df_pd);  df_pdp = _to_s(df_pdp)

            pt_cols_     = sorted([c for c in df_td.columns
                                   if c[0]=='s' and c[1:].isdigit()],
                                  key=lambda x: int(x[1:]))
            ind_td_start = df_td.columns.get_loc(pt_cols_[0])
            ind_td_end   = df_td.columns.get_loc(pt_cols_[-1])
            df_td  = df_td.fillna(0);  df_tdp = df_tdp.fillna(0)
            td     = df_td.iloc[0, ind_td_start:ind_td_end+1].to_numpy().astype(np.int8)

            def _pt_cols(df):
                return sorted([c for c in df.columns
                               if c[1:].isdigit() and c[0] in ('s','l')],
                              key=lambda x: int(x[1:]))

            def fill_nan_with_median(row):
                return row.fillna(row.median())

            self.progress.emit(30, "Building pattern deviation dataframes…")
            df_PDP = df_pdp[_pt_cols(df_pdp)].apply(fill_nan_with_median, axis=1)
            df_TD  = df_td[_pt_cols(df_td)].apply(fill_nan_with_median, axis=1)
            df_TDP = df_tdp[_pt_cols(df_tdp)].apply(fill_nan_with_median, axis=1)

            df_PDP = df_PDP.set_index(org_data.index)
            md_col = next((c for c in df_gi.columns if c.lower() in ('md','tmd')), None)
            df_PDP['MD']   = df_gi[md_col].values if md_col else 0.0
            df_PDP['Eye']  = df_input['eye']
            df_PDP['Date'] = df_input['date']
            df_PDP['ID']   = df_input['id']

            df_TD  = df_TD.set_index(org_data.index)
            df_TD['Eye']   = df_input['eye']
            df_TD['Date']  = df_input['date']
            df_TD['ID']    = df_input['id']

            df_TDP = df_TDP.set_index(org_data.index)
            df_TDP['Eye']  = df_input['eye']
            df_TDP['Date'] = df_input['date']
            df_TDP['ID']   = df_input['id']

            # ── Stage 2: classifiers ───────────────────────────────────────
            self.progress.emit(40, "Running UKGTS classifier…")
            df_UKGTS = Fn_UKGTS(df_TDP.copy());  df1 = df_UKGTS['UKGTS_clf']

            self.progress.emit(52, "Running LoGTS classifier…")
            df_LoGTS = Fn_LoGTS(df_TD.copy());   df2 = df_LoGTS['LoGTS_clf']

            self.progress.emit(62, "Running Foster classifier…")
            df_Foster = Fn_Foster(df_PDP.copy()); df3 = df_Foster['Foster_clf']

            self.progress.emit(72, "Running Kangs classifier…")
            df_Kangs = Fn_Kangs(df_TD.copy());    df4 = df_Kangs['Kangs_clf']

            self.progress.emit(82, "Running HAP2 classifier…")
            df_HAP2 = Fn_HAP2(df_PDP.copy())
            df5 = df_HAP2['HAP2_p1_clf'];  df6 = df_HAP2['HAP2_p2_clf']

            # ── Stage 3: weights + ensemble ────────────────────────────────
            self.progress.emit(88, "Computing ensemble decision…")
            stage_order    = ['Non-GL', 'GL']
            counts_ukgts   = df1.value_counts().reindex(stage_order).fillna(0)
            counts_logts   = df2.value_counts().reindex(stage_order).fillna(0)
            counts_foster  = df3.value_counts().reindex(stage_order).fillna(0)
            counts_kangs   = df4.value_counts().reindex(stage_order).fillna(0)
            counts_hap2_p1 = df5.value_counts().reindex(stage_order).fillna(0)

            class_samples = np.array([
                counts_ukgts.get('Non-GL',0),  counts_logts.get('Non-GL',0),
                counts_foster.get('Non-GL',0), counts_kangs.get('Non-GL',0),
                counts_hap2_p1.get('Non-GL',0),counts_ukgts.get('GL',0),
                counts_logts.get('GL',0),       counts_foster.get('GL',0),
                counts_kangs.get('GL',0),       counts_hap2_p1.get('GL',0)])
            total_samples = np.sum(class_samples)
            with np.errstate(divide='ignore', invalid='ignore'):
                weights = np.where(class_samples > 0,
                                   total_samples / (2 * class_samples), 1.0)
            weights = weights[int(.5*len(weights)):]
            weights = np.nan_to_num(weights, nan=1.0, posinf=1.0)

            result_combined    = Fn_ensemble_decision(df_input, df1, df2,
                                                      df3, df4, df5, weights)
            result_combined_en = result_combined.astype(str)

            def map_decision(v):
                return 'GL' if v > 0.5 else 'Non-GL'
            result_combined['Labels'] = result_combined['Ensemble'].apply(map_decision)

            self.progress.emit(100, "Done!")

            # pack everything the main thread needs
            self.finished.emit({
                'df_input': df_input, 'df_td': df_td, 'df_tdp': df_tdp,
                'df_gi': df_gi, 'df_pd': df_pd, 'df_pdp': df_pdp,
                'df_PDP': df_PDP, 'df_TD': df_TD, 'df_TDP': df_TDP,
                'df_UKGTS': df_UKGTS, 'df_LoGTS': df_LoGTS,
                'df_Foster': df_Foster, 'df_Kangs': df_Kangs, 'df_HAP2': df_HAP2,
                'df1': df1, 'df2': df2, 'df3': df3, 'df4': df4,
                'df5': df5, 'df6': df6,
                'result_combined': result_combined,
                'result_combined_en': result_combined_en,
                'counts_ukgts': counts_ukgts, 'counts_logts': counts_logts,
                'counts_foster': counts_foster, 'counts_kangs': counts_kangs,
                'counts_hap2_p1': counts_hap2_p1,
                'td': td,
            })

        except Exception as e:
            import traceback
            self.error.emit(traceback.format_exc())

