class ProgressDialog(QtWidgets.QDialog):
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setWindowTitle("Processing — PyGlaucoMetrics")
        self.setFixedSize(480, 180)
        self.setWindowFlags(self.windowFlags() |
                            QtCore.Qt.WindowStaysOnTopHint)
        self.setModal(True)

        layout = QtWidgets.QVBoxLayout(self)
        layout.setContentsMargins(20, 20, 20, 20)
        layout.setSpacing(12)

        # top label — live step name
        self.stage_label = QtWidgets.QLabel("Starting…")
        self.stage_label.setFont(QtGui.QFont("Segoe UI", 10, QtGui.QFont.Bold))
        layout.addWidget(self.stage_label)

        # progress bar
        self.bar = QtWidgets.QProgressBar()
        self.bar.setRange(0, 100)
        self.bar.setValue(0)
        self.bar.setTextVisible(True)
        self.bar.setFixedHeight(24)
        self.bar.setStyleSheet("""
            QProgressBar {
                border: 1px solid #bbb;
                border-radius: 5px;
                background: #f0f0f0;
                text-align: center;
                font-size: 10px;
            }
            QProgressBar::chunk {
                background: qlineargradient(
                    x1:0, y1:0, x2:1, y2:0,
                    stop:0 #4a90d9, stop:1 #1a5fa8);
                border-radius: 4px;
            }
        """)
        layout.addWidget(self.bar)

        # bottom label — stage summary
        self.detail_label = QtWidgets.QLabel("")
        self.detail_label.setFont(QtGui.QFont("Segoe UI", 8))
        self.detail_label.setStyleSheet("color: #555;")
        layout.addWidget(self.detail_label)

    # stage lookup — maps percent thresholds to summary strings
    _STAGES = {
        5:   "Stage 1/3 — Computing normative deviations",
        20:  "Stage 1/3 — Normalising output columns",
        30:  "Stage 1/3 — Building deviation dataframes",
        40:  "Stage 2/3 — Running classifiers (UKGTS)",
        52:  "Stage 2/3 — Running classifiers (LoGTS)",
        62:  "Stage 2/3 — Running classifiers (Foster)",
        72:  "Stage 2/3 — Running classifiers (Kangs)",
        82:  "Stage 2/3 — Running classifiers (HAP2)",
        88:  "Stage 3/3 — Computing ensemble decision",
        100: "Complete ✓",
    }

    def update_progress(self, percent, message):
        self.bar.setValue(percent)
        self.stage_label.setText(message)
        closest = min(self._STAGES, key=lambda k: abs(k - percent))
        self.detail_label.setText(self._STAGES[closest])
        QtWidgets.QApplication.processEvents()
