    def load_dataset(self):
        file_path, _ = QtWidgets.QFileDialog.getOpenFileName(
            None, "Open CSV File", "", "CSV Files (*.csv)")
        if file_path:
            try:
                org_data = pd.read_csv(file_path, encoding='windows-1254',
                                       low_memory=False)
                self._dataset_stem = os.path.splitext(os.path.basename(file_path))[0]

                QtWidgets.QMessageBox.information(
                    None, "Success", "CSV file loaded successfully!")
            except Exception as e:
                QtWidgets.QMessageBox.critical(
                    None, "Error", f"Error loading CSV file: {str(e)}")
                return
        else:
            return

        pd.options.mode.chained_assignment = None

        # ── normalise sensitivity column names to s1…s54 ──────────────────
        for prefix in ('l', 'p', 'sens', 'vf'):
            candidates = sorted(
                [c for c in org_data.columns
                 if c.startswith(prefix) and c[len(prefix):].isdigit()],
                key=lambda x: int(x[len(prefix):]))
            if len(candidates) >= 52:
                org_data = org_data.rename(
                    columns={c: f's{c[len(prefix):]}' for c in candidates})
                print(f"Renamed {len(candidates)} '{prefix}*' columns → 's*'")
                break

        # ── build df_input ────────────────────────────────────────────────
        required_columns = ['id', 'eye', 'date', 'time', 'age',
                            'type', 'fpr', 'fnr', 'fl', 'duration']
        required_columns.extend([f's{i}' for i in range(1, 55)])
        org_data.columns = org_data.columns.str.strip().str.lower()
        df_input = org_data.reindex(columns=required_columns, fill_value=np.nan)

        # ── date / time ───────────────────────────────────────────────────
        if 'timeoftest' in org_data.columns:
            raw_tot = org_data['timeoftest'].astype(str)
            def _parse_tot(s):
                s = s.strip()
                if len(s) == 10:
                    return pd.to_datetime(s[:6], format='%y%m%d', errors='coerce')
                if len(s) == 8:
                    return pd.to_datetime(s, format='%Y%m%d', errors='coerce')
                return pd.NaT
            df_input['date'] = raw_tot.apply(_parse_tot)
        elif 'date' in org_data.columns:
            df_input['date'] = pd.to_datetime(org_data['date'], errors='coerce')
        else:
            df_input['date'] = pd.Timestamp.now()

        df_input['time'] = org_data['time'].astype(object) \
            if 'time' in org_data.columns else '00:00'

        # ── eye column ────────────────────────────────────────────────────
        if 'righteye' in org_data.columns:
            df_input['eye'] = org_data['righteye'].apply(
                lambda x: 'OD' if x == 1 else 'OS')
        df_input['eye'] = df_input['eye'].apply(
            lambda x: _normalise_eye(x) or 'OD')

        # ── dtypes ────────────────────────────────────────────────────────
        df_input['id']  = df_input['id'].astype('int32', errors='ignore')
        df_input['age'] = pd.to_numeric(
            df_input['age'], errors='coerce').fillna(60).astype('int32')
        df_input[['fpr','fnr','fl','duration']] = \
            df_input[['fpr','fnr','fl','duration']].astype('float64', errors='ignore')
        s_cols = [f's{i}' for i in range(1, 55)]
        df_input[s_cols] = df_input[s_cols].astype('int32', errors='ignore')

        # diagnostic
        n_valid = df_input[s_cols].notna().sum(axis=1).iloc[0]
        print(f"Row-0 non-NaN sensitivity values: {n_valid}/54 "
              f"| sample: {df_input[s_cols[:5]].iloc[0].tolist()}")

        # ── launch worker ─────────────────────────────────────────────────
        self._progress_dlg = ProgressDialog(None)
        self._progress_dlg.show()
        QtWidgets.QApplication.processEvents()

        self._worker = ProcessingWorker(org_data, df_input)
        self._worker.progress.connect(self._progress_dlg.update_progress)
        self._worker.finished.connect(self._on_processing_done)
        self._worker.error.connect(self._on_processing_error)
        self._worker.start()
        ######################################################################################################
    def _on_processing_done(self, results):
        self._progress_dlg.close()
        self.df_input        = results['df_input']
        n_rows = len(results['df_input'])
        self.label_id_range.setText(
            f"Enter index in range  0 → {n_rows - 1}  "
            f"({n_rows:,} exams loaded)"
        )
        self.label_id_range.setStyleSheet(
            "color: #1a5fa8; font-weight: bold; "
            "padding: 3px 8px; background: #e8f0fb; "
            "border: 1px solid #b0c8e8; border-radius: 4px;"
        )
        self.df_TDP          = results['df_TDP']
        self.df_PDP          = results['df_PDP']
        self.df_TD           = results['df_TD']
        self.df_UKGTS        = results['df_UKGTS']
        self.df_LoGTS        = results['df_LoGTS']
        self.df_Foster       = results['df_Foster']
        self.df_Kangs        = results['df_Kangs']
        self.df_HAP2         = results['df_HAP2']
        self.result_combined = results['result_combined']
        self.result_combined_en = results['result_combined_en']
        self.df1 = results['df1'];  self.df2 = results['df2']
        self.df3 = results['df3'];  self.df4 = results['df4']
        self.df5 = results['df5'];  self.df6 = results['df6']
        self.counts_ukgts    = results['counts_ukgts']
        self.counts_logts    = results['counts_logts']
        self.counts_foster   = results['counts_foster']
        self.counts_kangs    = results['counts_kangs']
        self.counts_hap2_p1  = results['counts_hap2_p1']
        QtWidgets.QMessageBox.information(
            None, "Success",
            "Dataset processed!\nEnter an ID to view predictions.")

    def _on_processing_error(self, tb):
        self._progress_dlg.close()
        QtWidgets.QMessageBox.critical(
            None, "Processing Error",
            f"An error occurred:\n\n{tb}")

    def get_prediction(self):
        df_input=self.df_input
        df1=self.df1
        df2=self.df2
        df3=self.df3
        df4=self.df4
        df5=self.df5
        df6=self.df6
        #df7=self.df7
        result_combined=self.result_combined
        result_combined_en=self.result_combined_en
        ############################################################ ICC
        counts_ukgts = self.counts_ukgts
        counts_logts = self.counts_logts
        #counts_ght = self.counts_ght
        counts_foster = self.counts_foster
        counts_kangs = self.counts_foster
        counts_hap2_p1 = self.counts_hap2_p1
        ###############################################################
        input_text = self.lineEdit.text()  # Get the text from QLineEdit
        # Create a progress dialog
        progress_dialog = QProgressDialog("Generating plots...", None, 0, 0)
        progress_dialog.setWindowModality(QtCore.Qt.WindowModal)
        progress_dialog.setMinimumDuration(0)
        progress_dialog.show()
        try:
            input_number = int(self.lineEdit.text())
            vf = self.df_input.iloc[[input_number]]

            # ── Sensitivity ──────────────────────────────────────────────────
            visualFields.vfplot(vf, type='s', save=True, filename='sensitivity', fmt='png')
            img_bytes1 = BytesIO()
            Image.open("sensitivity.png").save(img_bytes1, format='PNG')
            img_bytes1.seek(0)
            pixmap1 = QPixmap()
            pixmap1.loadFromData(img_bytes1.getvalue())

            # ── TD probability ───────────────────────────────────────────────
            visualFields.vfplot_tds(vf, save=True, filename='tdp', fmt='png')
            img_bytes2 = BytesIO()
            Image.open("tdp.png").save(img_bytes2, format='PNG')
            img_bytes2.seek(0)
            pixmap2 = QPixmap()
            pixmap2.loadFromData(img_bytes2.getvalue())

            # ── PD probability ───────────────────────────────────────────────
            visualFields.vfplot_pds(vf, save=True, filename='pdp', fmt='png')
            img_bytes3 = BytesIO()
            Image.open("pdp.png").save(img_bytes3, format='PNG')
            img_bytes3.seek(0)
            pixmap3 = QPixmap()
            pixmap3.loadFromData(img_bytes3.getvalue())

            # ── Display — all three scaled to the same target size ───────────
            _TARGET = QtCore.QSize(440, 440)
            self.label_2.setPixmap(
                pixmap1.scaled(_TARGET, QtCore.Qt.KeepAspectRatio,
                               QtCore.Qt.SmoothTransformation))
            self.label_3.setPixmap(
                pixmap2.scaled(_TARGET, QtCore.Qt.KeepAspectRatio,
                               QtCore.Qt.SmoothTransformation))
            self.label_4.setPixmap(
                pixmap3.scaled(_TARGET, QtCore.Qt.KeepAspectRatio,
                               QtCore.Qt.SmoothTransformation))
            ###########################################
            ukgts=df1.iloc[[input_number]]
            logts=df2.iloc[[input_number]]
            #ght=df3.iloc[[input_number]]
            foster=df3.iloc[[input_number]]
            kangs=df4.iloc[[input_number]]
            hap2_p1=df5.iloc[[input_number]]
            hap2_p2=df6.iloc[[input_number]]
            ensemble=result_combined.iloc[[input_number]]
            ensemble_name = ensemble['Labels'].values[0]
            gl_prob= ensemble['Ensemble'].values[0]
            gl_prob=round(100*gl_prob,2)
            ngl_prob=round(100-gl_prob,2)
            ## Extract the name and stage from the prediction Series
            ukgts_name = ukgts.name
            ukgts_dec = ukgts.values[0]  # Assuming stage is the first value in the Series
            logts_name = logts.name
            logts_dec = logts.values[0]  # Assuming stage is the first value in the Series
            #ght_name = ght.name
            #ght_dec = ght.values[0]  # Assuming stage is the first value in the Series
            foster_name = foster.name
            foster_dec = foster.values[0]  # Assuming stage is the first value in the Series
            kangs_name = kangs.name
            kangs_dec = kangs.values[0]  # Assuming stage is the first value in the Series
            hap2_p1_name = hap2_p1.name
            hap2_p1_dec = hap2_p1.values[0]  # Assuming stage is the first value in the Series
            hap2_p2_name = hap2_p2.name
            hap2_p2_dec = hap2_p2.values[0]  # Assuming stage is the first value in the Series
            
            ############################################
            # Check agreement/disagreement
            # Intraclass Correlation Coefficient (ICC) 
            non_gl_all = [counts_hap2_p1.get('Non-GL', 0), counts_ukgts.get('Non-GL', 0), counts_logts.get('Non-GL', 0), counts_kangs.get('Non-GL', 0), counts_foster.get('Non-GL', 0)]
            gl_all = [counts_hap2_p1.get('GL', 0), counts_ukgts.get('GL', 0), counts_logts.get('GL', 0), counts_kangs.get('GL', 0), counts_foster.get('GL', 0)]
            #1- UKGTS & LoGTS
            non_gl_ukgts_logts = [counts_ukgts.get('Non-GL', 0), counts_logts.get('Non-GL', 0)]
            gl_ukgts_logts = [counts_ukgts.get('GL', 0), counts_logts.get('GL', 0)]
            #2- HAP2_part1 & UKGTS
            non_gl_hap2p1_ukgts = [counts_hap2_p1.get('Non-GL', 0), counts_ukgts.get('Non-GL', 0)]
            gl_hap2p1_ukgts = [counts_hap2_p1.get('GL', 0), counts_ukgts.get('GL', 0)]
            #3- HAP2_part1 & LoGTS
            non_gl_hap2p1_logts = [counts_hap2_p1.get('Non-GL', 0), counts_logts.get('Non-GL', 0)]
            gl_hap2p1_logts = [counts_hap2_p1.get('GL', 0), counts_logts.get('GL', 0)]
            #4- HAP2_part1 & Kangs
            non_gl_hap2p1_kangs = [counts_hap2_p1.get('Non-GL', 0), counts_kangs.get('Non-GL', 0)]
            gl_hap2p1_kangs = [counts_hap2_p1.get('GL', 0), counts_kangs.get('GL', 0)]
            #5- Kangs & UKGTS
            non_gl_kangs_ukgts = [counts_kangs.get('Non-GL', 0), counts_ukgts.get('Non-GL', 0)]
            gl_kangs_ukgts = [counts_kangs.get('GL', 0), counts_ukgts.get('GL', 0)]
            #6- HAP2_part1 & Foster
            non_gl_hap2p1_foster = [counts_hap2_p1.get('Non-GL', 0), counts_foster.get('Non-GL', 0)]
            gl_hap2p1_foster = [counts_hap2_p1.get('GL', 0), counts_foster.get('GL', 0)]


            # Combine the data into a list of arrays
            data_all = [non_gl_all, gl_all]
            data_ukgts_logts = [non_gl_ukgts_logts, gl_ukgts_logts]
            data_hap2p1_ukgts = [non_gl_hap2p1_ukgts, gl_hap2p1_ukgts]
            data_hap2p1_logts = [non_gl_hap2p1_logts, gl_hap2p1_logts]
            data_hap2p1_kangs = [non_gl_hap2p1_kangs, gl_hap2p1_kangs]
            data_kangs_ukgts = [non_gl_kangs_ukgts, gl_kangs_ukgts]
            data_hap2p1_foster = [non_gl_hap2p1_foster, gl_hap2p1_foster]

            # Perform one-way ANOVA to obtain the total variance
            total_variance_all = np.var(np.concatenate(data_all))
            total_variance_ukgts_logts = np.var(np.concatenate(data_ukgts_logts))
            total_variance_hap2p1_ukgts = np.var(np.concatenate(data_hap2p1_ukgts))
            total_variance_hap2p1_logts = np.var(np.concatenate(data_hap2p1_logts))
            total_variance_hap2p1_kangs = np.var(np.concatenate(data_hap2p1_kangs))
            total_variance_kangs_ukgts = np.var(np.concatenate(data_kangs_ukgts))
            total_variance_hap2p1_foster = np.var(np.concatenate(data_hap2p1_foster))

            # Calculate the residual variance (within-group variance)
            residual_variance_all = np.mean([np.var(arr) for arr in data_all])
            residual_variance_ukgts_logts = np.mean([np.var(arr) for arr in data_ukgts_logts])
            residual_variance_hap2p1_ukgts = np.mean([np.var(arr) for arr in data_hap2p1_ukgts])
            residual_variance_hap2p1_logts = np.mean([np.var(arr) for arr in data_hap2p1_logts])
            residual_variance_hap2p1_kangs = np.mean([np.var(arr) for arr in data_hap2p1_kangs])
            residual_variance_kangs_ukgts = np.mean([np.var(arr) for arr in data_kangs_ukgts])
            residual_variance_hap2p1_foster = np.mean([np.var(arr) for arr in data_hap2p1_foster])

            def _safe_icc(tv, rv):
                return 1.0 if tv == 0 else (tv - rv) / tv

            icc_all           = _safe_icc(total_variance_all,           residual_variance_all)
            icc_ukgts_logts   = _safe_icc(total_variance_ukgts_logts,   residual_variance_ukgts_logts)
            icc_hap2p1_ukgts  = _safe_icc(total_variance_hap2p1_ukgts,  residual_variance_hap2p1_ukgts)
            icc_hap2p1_logts  = _safe_icc(total_variance_hap2p1_logts,  residual_variance_hap2p1_logts)
            icc_hap2p1_kangs  = _safe_icc(total_variance_hap2p1_kangs,  residual_variance_hap2p1_kangs)
            icc_kangs_ukgts   = _safe_icc(total_variance_kangs_ukgts,   residual_variance_kangs_ukgts)
            icc_hap2p1_foster = _safe_icc(total_variance_hap2p1_foster, residual_variance_hap2p1_foster)

            icc_values = {
                "UKGTS and LoGTS": icc_ukgts_logts,
                "HAP2_part1 and UKGTS": icc_hap2p1_ukgts,
                "HAP2_part1 and LoGTS": icc_hap2p1_logts,
                #"HAP2_part2 and UKGTS": icc_hap2p2_ukgts,
                #"HAP2_part2 and LoGTS": icc_hap2p2_logts,
                "HAP2_part1 and Kangs": icc_hap2p1_kangs,
                "Kangs and UKGTS": icc_kangs_ukgts,
                "HAP2_part1 and Foster": icc_hap2p1_foster
            }

            # Find the pair with the highest ICC
            best_pair = max(icc_values, key=icc_values.get)
            best_icc = icc_values[best_pair]
            
            #############################################
            self.label_6.setText(
                f"Total Agreemnt= {icc_all*100:.1f}\n"
                f"Stand-alone prediction:\n{ukgts_name}: {ukgts_dec}\n"
                f"{logts_name}: {logts_dec}\n"
                f"{foster_name}: {foster_dec}\n{kangs_name}: {kangs_dec}\n"
                f"HAP2: {hap2_p1_dec}({hap2_p2_dec})\n"
                f"Best Agreement:\n"
                f"{best_pair}, ICC={best_icc*100:.1f}%"
            )
            self.label_7.setText(
                f"Ensemble: {ensemble_name}\n"
                f"GL Probability= {gl_prob}%\n"
                f"Non-Glaucoma= {ngl_prob}%"
                )
            
        except ValueError:
            QMessageBox.warning(None, "Invalid Input", "Please enter a valid integer.")

        progress_dialog.close()

    def checked(self):
        directory_path = QFileDialog.getExistingDirectory(None, "Select Directory To Save Results")
        if not directory_path:
            return

        import shutil
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        stem = getattr(self, '_dataset_stem', 'dataset')

        # ── Save VF plot PNGs (each contains its own colormap strip) ─────────
        for src_name, label in (('sensitivity.png', 'Sensitivity'),
                                 ('tdp.png',         'TD'),
                                 ('pdp.png',         'PD')):
            if os.path.exists(src_name):
                shutil.copy2(src_name,
                             os.path.join(directory_path,
                                          f'{stem}_{label}_plot_{timestamp}.png'))
            else:
                QtWidgets.QMessageBox.warning(
                    None, "Missing plot",
                    f"{src_name} not found — run a prediction first.")

        # ── Save classifier CSVs ──────────────────────────────────────────────
        dataframes = {
            'TDP_data':  self.df_TDP,
            'PDP_data':  self.df_PDP,
            'HAP2_clf':  self.df_HAP2,
            'UKGTS_clf': self.df_UKGTS,
            'LoGTS_clf': self.df_LoGTS,
            'Kangs_clf': self.df_Kangs,
            'Foster_clf':self.df_Foster,
            'Ensemble':  self.result_combined,
        }
        for name, df in dataframes.items():
            df.to_csv(os.path.join(directory_path,
                                   f'{stem}_{name}_{timestamp}.csv'), index=False)

        # ── HAP2 stage bar chart ──────────────────────────────────────────────
        df_od = self.df_HAP2[self.df_HAP2['Eye'] == 'OD']
        df_os = self.df_HAP2[self.df_HAP2['Eye'] == 'OS']
        stage_order = ['Stage 1', 'Stage 2', 'Stage 3']
        df_both = pd.concat([df_od, df_os])
        plt.figure(figsize=(10, 6))
        ax = sns.countplot(x='HAP2_p2_clf', data=df_both, hue='Eye',
                           palette={'OD': 'blue', 'OS': 'cyan'}, order=stage_order)
        plt.title('Classification Results for OD and OS Eyes: HAP2_part2')
        plt.xlabel('Stage'); plt.ylabel('Count')
        plt.legend(title='Eye', loc='upper right')
        for p in ax.patches:
            ax.annotate(format(p.get_height(), '.0f'),
                        (p.get_x() + p.get_width() / 2., p.get_height()),
                        ha='center', va='center', xytext=(0, 10),
                        textcoords='offset points')
        plt.savefig(os.path.join(directory_path,
                                  f'{stem}_HAP2_part2_classification_results_{timestamp}.png'))
        plt.close()

        # ── Final ensemble bar chart ──────────────────────────────────────────
        stage_order = ['Non-GL', 'GL']
        counts_ensemble = self.result_combined['Labels'].value_counts().reindex(stage_order)
        tot_counts = pd.DataFrame({
            'HAP2_p1_clf': self.counts_hap2_p1,
            'UKGTS_clf':   self.counts_ukgts,
            'LoGTS_clf':   self.counts_logts,
            'Kangs_clf':   self.counts_kangs,
            'Foster_clf':  self.counts_foster,
            'Ensemble':    counts_ensemble,
        })
        bar_width = 0.13
        r1 = np.arange(len(stage_order))
        positions = [r1 + i * bar_width for i in range(6)]
        fig, ax = plt.subplots()
        labels  = ['HAP2_p1_clf','UKGTS_clf','LoGTS_clf','Kangs_clf','Foster_clf','Ensemble']
        series  = [self.counts_hap2_p1, self.counts_ukgts, self.counts_logts,
                   self.counts_kangs, self.counts_foster, counts_ensemble]
        for pos, ser, lbl in zip(positions, series, labels):
            ax.bar(pos, ser, width=bar_width, edgecolor='grey', label=lbl)
        for i, (pos, ser) in enumerate(zip(positions, series)):
            for j, val in enumerate(pos):
                ax.text(val, tot_counts.iloc[j, i] + 0.05,
                        str(tot_counts.iloc[j, i]), ha='center', va='bottom')
        ax.set_xlabel('Class'); ax.set_ylabel('Count')
        ax.set_xticks([r + 2.5 * bar_width for r in range(len(stage_order))])
        ax.set_xticklabels(stage_order)
        ax.legend()
        fig.savefig(os.path.join(directory_path,
                                  f'{stem}_Final_classification_results_{timestamp}.png'))
        plt.close()

        QtWidgets.QMessageBox.information(None, "Done", "Files saved successfully")
